import json
from langgraph.checkpoint.sqlite import SqliteSaver
import sqlite3

class StateBloatDetector:
    def __init__(self, db_path):
        self.db_path = db_path

    def find_bloated_states(self, size_threshold_kb=50):
        conn = sqlite3.connect(self.db_path)
        bloated = []
        for row in conn.execute('SELECT * FROM checkpointer_writes'):
            state_size = len(row[3]) / 1024  # checkpoint column
            if state_size > size_threshold_kb:
                bloated.append({
                    'thread_id': row[0],
                    'size_kb': state_size,
                    'checkpoint_ts': row[1]
                })
        return bloated

# Usage
detector = StateBloatDetector('agent_checkpoints.db')
bloat = detector.find_bloated_states()
print(f'Bloated states: {len(bloat)}')
